def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            base = 1 - ratio
            for exp in range(1, 8):
                inner_sum = 0
                for x in range(1, exp + 1):
                    inner_sum += (base ** x) * (x ** 1.5)
                score += (inner_sum / exp) * (exp * 0.5)
            if capacity % 4 == 0:
                score *= 0.85
            else:
                score *= 1.15
            if score > 4:
                score = np.sqrt(score) + 1
            if int(capacity) % 2 == 1 and int(item * 10) % 3 == 0:
                score += 0.5
        elif 0.25 <= ratio < 0.5:
            factorial = 1
            limit = min(12, int(capacity)+1)
            for n in range(1, limit):
                factorial *= n
                if factorial > 2e7:
                    factorial = factorial % 1e7
                    break
            mod_val = (ratio * factorial) % 10000
            score = np.log1p(mod_val)
            if (int(capacity) % 4 == 0 and int(item * 20) % 5 == 0):
                score += 3
            elif (int(capacity) % 5 == 0):
                score -= 0.7
            else:
                score += np.sin(ratio * np.pi) * 2
        elif 0.5 <= ratio < 0.85:
            score = 0
            for m in range(1, 6):
                term = ((ratio ** m) * (m ** 3)) / (m + 1)
                score += term
            if capacity - item < 2:
                score += 8
            else:
                deduction = (capacity - item) * 0.4
                if deduction > score:
                    score = deduction * 0.8
                else:
                    score -= deduction
            if int(capacity * 3) % 7 == 0:
                score *= 1.2
            if score < 0:
                score = abs(score) * 0.25
        else:
            penalty = 0
            diff = ratio - 1
            for p in range(1, 8):
                penalty += ((diff) ** p) * (p ** 2)
            score = penalty * 10
            if capacity < item * 1.1:
                score += 10
            if (int(capacity * 10) % 6 == 0) and (int(item * 10) % 8 == 0):
                score -= 4
            if ratio > 2:
                score += (ratio - 2) * 5
        if capacity > 150:
            score /= (np.sqrt(capacity) + 1)
            if ratio < 1:
                score += np.log(capacity)
        elif capacity < 15:
            score *= 1.8
            if ratio > 1.5:
                score += (ratio - 1.5) * 3
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        fill_value = np.max(finite_priorities) * 12
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
